import{C as t,o as e,c as l,a5 as i,E as h}from"./chunks/framework.CW28V7p_.js";const o=JSON.parse('{"title":"4. Linux processes & daemons","description":"","frontmatter":{},"headers":[],"relativePath":"module-0/4-processes.md","filePath":"module-0/4-processes.md","lastUpdated":1780937944000}'),p={name:"module-0/4-processes.md"},F=Object.assign(p,{setup(k){const a={id:"m0-4-processes",title:"🧠 Mini-check: Linux processes & daemons",intro:"3 питання — фокус на systemd і daemons.",questions:[{type:"compare",q:"У чому різниця між foreground process і daemon? Перерахуй 3 пункти.",ideal:`1. Foreground process прив'язаний до твого terminal session — якщо закриєш SSH, він вб'ється (SIGHUP). Daemon відв'язаний від terminal, працює навіть якщо ти logoutишся.
2. Foreground process пише stdout/stderr напряму у твій terminal. Daemon пише в лог-файли або journald.
3. Foreground process має parent = твій shell. Daemon має parent = init (PID 1, systemd), тобто запускається через init system а не з shell напряму.
4. Foreground process ти бачиш у терміналі коли він біжить. Daemon працює невидимо у background, перевіряєш через ps/systemctl.`,explanation:"Ключове — daemon відв'язаний від TTY/session і працює як background service під керуванням init системи. Якщо ти описала ці два аспекти (no terminal + managed by systemd/init) — це повна відповідь."},{type:"command",q:"Як подивитись live logs solana service (last 50 рядків + tail follow)? Напиши команду.",accepts:["sudo journalctl -u solana -n 50 -f","sudo journalctl -u solana.service -n 50 -f","journalctl -u solana -n 50 -f","sudo journalctl -fu solana -n 50"],ideal:"sudo journalctl -u solana -n 50 -f",explanation:"journalctl читає systemd journal logs. -u solana фільтрує по unit. -n 50 показує останні 50 рядків як стартову точку. -f (follow) дотягує нові рядки live (як tail -f). sudo потрібен бо journal може бути restricted to root/adm group."},{type:"diagnose",q:'systemctl status solana показує: "Active: failed (Result: exit-code)" і "Process: 12345 ExecStart=... (code=exited, status=1/FAILURE)". Що з цих причин могло це викликати (обери всі правдоподібні)?',options:["У ExecStart рядку є typo або неправильний флаг — validator immediately exited","Файл validator-keypair.json не існує або неправильні permissions","Hardware failure (диск помер)","Validator потребує більше RAM ніж є на сервері"],correct:[0,1],explanation:"status=1/FAILURE означає validator binary запустився але exit-нув з кодом 1 (помилка). Типові причини — неправильний CLI flag (опечатка у ExecStart) або відсутній/non-readable файл. Hardware failure спричинив би різний error pattern (Active: failed + raw error у logs). OOM kill спричинив би status=9/KILL не status=1."}]};return(r,s)=>{const n=t("Quiz");return e(),l("div",null,[s[0]||(s[0]=i("",54)),h(n,{data:a}),s[1]||(s[1]=i("",6))])}}});export{o as __pageData,F as default};
